	// Register external tool
	reg := agentictools.ExternalToolRegistration{
		Name:        "git_status",
		Description: "Get git status",
		Parameters:  map[string]interface{}{"type": "object"},
		Provider:    "semspec",
		Timestamp:   time.Now(),
	}

